{
  "name": "Sistema de Orçamento Profissional",
  "description": "Uma aplicação moderna e profissional para criação de orçamentos, com upload de imagens, cálculos automáticos e exportação para PDF, mantendo a estrutura clássica de planilhas comerciais.",
  "requestFramePermissions": [
    "camera"
  ]
}

export interface ClientData {
  name: string;
  address: string;
  phone: string;
  cep: string;
  cityState: string;
  date: string;
  quoteNumber: string;
}

export interface QuoteItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
  image?: string;
}

export interface CompanyInfo {
  name: string;
  address: string;
  cnpj: string;
  email: string;
  phone: string;
  website: string;
}

import { CompanyInfo } from './types';

export const COMPANY_INFO: CompanyInfo = {
  name: "SOLUÇÕES PRO LTDA",
  address: "Av. Paulista, 1000 - Bela Vista, São Paulo - SP",
  cnpj: "12.345.678/0001-90",
  email: "contato@solucoespro.com.br",
  phone: "(11) 98765-4321",
  website: "www.solucoespro.com.br"
};

export const DEFAULT_OBSERVATIONS = "1. Orçamento válido por 15 dias.\n2. Prazo de entrega: 5 a 10 dias úteis após aprovação.\n3. Condições de pagamento: 50% entrada e saldo na entrega.\n4. Garantia de 12 meses contra defeitos de fabricação.";

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useMemo, useCallback } from 'react';
import { Plus, Trash2, Printer, Download, Eye, Image as ImageIcon, Briefcase, User, FileText, Calculator } from 'lucide-react';
import { ClientData, QuoteItem } from './types';
import { COMPANY_INFO, DEFAULT_OBSERVATIONS } from './constants';

const App: React.FC = () => {
  // State for editable fields
  const [clientData, setClientData] = useState<ClientData>({
    name: '',
    address: '',
    phone: '',
    cep: '',
    cityState: '',
    date: new Date().toLocaleDateString('pt-BR'),
    quoteNumber: `ORC-${Math.floor(1000 + Math.random() * 9000)}`,
  });

  const [items, setItems] = useState<QuoteItem[]>([
    { id: '1', description: '', quantity: 1, unitPrice: 0 }
  ]);

  const [observations, setObservations] = useState(DEFAULT_OBSERVATIONS);

  // Calculations (Non-editable logic)
  const subtotal = useMemo(() => {
    return items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  }, [items]);

  const taxRate = 0; // Fixed zero for now as per instructions (fórmulas fixas)
  const total = subtotal + (subtotal * taxRate);

  // Handlers
  const handleClientChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setClientData(prev => ({ ...prev, [name]: value }));
  };

  const addItem = () => {
    setItems(prev => [
      ...prev,
      { id: Math.random().toString(36).substr(2, 9), description: '', quantity: 1, unitPrice: 0 }
    ]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(prev => prev.filter(item => item.id !== id));
    }
  };

  const updateItem = (id: string, field: keyof QuoteItem, value: any) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const handleImageUpload = (id: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        updateItem(id, 'image', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handlePrint = () => {
    window.print();
  };

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);
  };

  return (
    <div className="min-h-screen py-8 px-4 sm:px-6 lg:px-8">
      <div className="max-w-5xl mx-auto bg-white shadow-xl rounded-xl overflow-hidden border border-gray-200" id="quote-container">

        {/* HEADER - ESTRUTURA FIXA */}
        <header className="bg-slate-800 text-white p-8 flex flex-col md:flex-row justify-between items-center">
          <div className="flex items-center space-x-4 mb-4 md:mb-0">
            <div className="bg-white p-3 rounded-lg shadow-inner">
              <Briefcase className="text-slate-800 w-10 h-10" />
            </div>
            <div>
              <h1 className="text-2xl font-bold tracking-tight">{COMPANY_INFO.name}</h1>
              <p className="text-slate-300 text-sm">{COMPANY_INFO.address}</p>
              <p className="text-slate-300 text-sm">CNPJ: {COMPANY_INFO.cnpj}</p>
            </div>
          </div>
          <div className="text-right text-sm">
            <p>{COMPANY_INFO.email}</p>
            <p>{COMPANY_INFO.phone}</p>
            <p>{COMPANY_INFO.website}</p>
          </div>
        </header>

        {/* DADOS DO CLIENTE - EDITÁVEL */}
        <section className="p-8 border-b border-gray-100">
          <div className="flex items-center space-x-2 mb-6 text-slate-700">
            <User className="w-5 h-5" />
            <h2 className="text-lg font-semibold uppercase tracking-wider">Dados do Cliente</h2>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="md:col-span-2">
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Nome do Cliente</label>
              <input
                type="text"
                name="name"
                value={clientData.name}
                onChange={handleClientChange}
                placeholder="Ex: João da Silva"
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-slate-500 focus:border-transparent outline-none transition-all"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Data do Orçamento</label>
              <input
                type="text"
                name="date"
                value={clientData.date}
                onChange={handleClientChange}
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-slate-500 outline-none"
              />
            </div>
            <div className="md:col-span-2">
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Endereço Completo</label>
              <input
                type="text"
                name="address"
                value={clientData.address}
                onChange={handleClientChange}
                placeholder="Rua, Número, Bairro"
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-slate-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Nº do Orçamento</label>
              <input
                type="text"
                name="quoteNumber"
                value={clientData.quoteNumber}
                onChange={handleClientChange}
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-slate-500 outline-none font-mono text-slate-700 font-bold"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Telefone / WhatsApp</label>
              <input
                type="text"
                name="phone"
                value={clientData.phone}
                onChange={handleClientChange}
                placeholder="(00) 00000-0000"
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-slate-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">CEP</label>
              <input
                type="text"
                name="cep"
                value={clientData.cep}
                onChange={handleClientChange}
                placeholder="00000-000"
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-slate-500 outline-none"
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Cidade / Estado</label>
              <input
                type="text"
                name="cityState"
                value={clientData.cityState}
                onChange={handleClientChange}
                placeholder="Cidade - UF"
                className="w-full px-4 py-2 border border-gray-300 rounded-md focus:ring-2 focus:ring-slate-500 outline-none"
              />
            </div>
          </div>
        </section>

        {/* ITENS DO ORÇAMENTO - EDITÁVEL (ESTRUTURA PLANILHA) */}
        <section className="p-8">
          <div className="flex items-center justify-between mb-6 text-slate-700">
            <div className="flex items-center space-x-2">
              <FileText className="w-5 h-5" />
              <h2 className="text-lg font-semibold uppercase tracking-wider">Itens do Orçamento</h2>
            </div>
            <button
              onClick={addItem}
              className="no-print flex items-center space-x-2 bg-slate-800 hover:bg-slate-700 text-white px-4 py-2 rounded-lg transition-colors text-sm font-medium shadow-sm"
            >
              <Plus className="w-4 h-4" />
              <span>Adicionar Item</span>
            </button>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full border-collapse">
              <thead>
                <tr className="bg-slate-100 border-b-2 border-slate-300">
                  <th className="px-4 py-3 text-left text-xs font-bold text-slate-600 uppercase tracking-wider w-1/12">Foto</th>
                  <th className="px-4 py-3 text-left text-xs font-bold text-slate-600 uppercase tracking-wider">Descrição do Produto / Serviço</th>
                  <th className="px-4 py-3 text-center text-xs font-bold text-slate-600 uppercase tracking-wider w-24">Qtd.</th>
                  <th className="px-4 py-3 text-right text-xs font-bold text-slate-600 uppercase tracking-wider w-32">Unitário</th>
                  <th className="px-4 py-3 text-right text-xs font-bold text-slate-600 uppercase tracking-wider w-32">Total</th>
                  <th className="px-4 py-3 text-center text-xs font-bold text-slate-600 uppercase tracking-wider w-12 no-print"></th>
                </tr>
              </thead>
              <tbody>
                {items.map((item, index) => (
                  <tr key={item.id} className="border-b border-gray-200 hover:bg-gray-50 transition-colors">
                    <td className="px-4 py-4">
                      <div className="relative group w-16 h-16 bg-gray-100 rounded-md flex items-center justify-center overflow-hidden border border-gray-300">
                        {item.image ? (
                          <img src={item.image} alt="Preview" className="w-full h-full object-cover" />
                        ) : (
                          <ImageIcon className="text-gray-400 w-6 h-6" />
                        )}
                        <input
                          type="file"
                          accept="image/*"
                          onChange={(e) => handleImageUpload(item.id, e)}
                          className="absolute inset-0 opacity-0 cursor-pointer no-print"
                        />
                      </div>
                    </td>
                    <td className="px-4 py-4">
                      <textarea
                        rows={1}
                        value={item.description}
                        onChange={(e) => updateItem(item.id, 'description', e.target.value)}
                        placeholder="Descreva o item ou serviço..."
                        className="w-full bg-transparent border-none focus:ring-0 resize-none outline-none text-gray-700"
                      />
                    </td>
                    <td className="px-4 py-4 text-center">
                      <input
                        type="number"
                        min="1"
                        value={item.quantity}
                        onChange={(e) => updateItem(item.id, 'quantity', Number(e.target.value))}
                        className="w-full text-center bg-transparent border-none focus:ring-0 outline-none"
                      />
                    </td>
                    <td className="px-4 py-4 text-right">
                      <input
                        type="number"
                        step="0.01"
                        value={item.unitPrice}
                        onChange={(e) => updateItem(item.id, 'unitPrice', Number(e.target.value))}
                        className="w-full text-right bg-transparent border-none focus:ring-0 outline-none"
                      />
                    </td>
                    <td className="px-4 py-4 text-right font-semibold text-slate-800">
                      {formatCurrency(item.quantity * item.unitPrice)}
                    </td>
                    <td className="px-4 py-4 text-center no-print">
                      <button
                        onClick={() => removeItem(item.id)}
                        className="text-red-400 hover:text-red-600 transition-colors p-1"
                        title="Remover"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        {/* OBSERVAÇÕES E TOTAIS */}
        <section className="p-8 bg-gray-50 border-t border-gray-100 grid grid-cols-1 md:grid-cols-2 gap-12">
          {/* OBSERVAÇÕES EDITÁVEIS */}
          <div>
            <div className="flex items-center space-x-2 mb-4 text-slate-700">
              <FileText className="w-4 h-4" />
              <h3 className="text-sm font-bold uppercase tracking-wider">Observações Importantes</h3>
            </div>
            <textarea
              rows={5}
              value={observations}
              onChange={(e) => setObservations(e.target.value)}
              className="w-full bg-white p-4 border border-gray-300 rounded-lg text-sm text-gray-600 focus:ring-2 focus:ring-slate-500 outline-none"
            />
          </div>

          {/* TOTAIS NÃO EDITÁVEIS (CÁLCULOS) */}
          <div className="flex flex-col justify-end space-y-4">
            <div className="flex items-center space-x-2 mb-2 text-slate-700">
              <Calculator className="w-4 h-4" />
              <h3 className="text-sm font-bold uppercase tracking-wider">Resumo de Valores</h3>
            </div>
            <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm space-y-3">
              <div className="flex justify-between text-gray-600 font-medium">
                <span>Subtotal:</span>
                <span>{formatCurrency(subtotal)}</span>
              </div>
              <div className="flex justify-between text-gray-400 text-sm">
                <span>Impostos estimados (0%):</span>
                <span>R$ 0,00</span>
              </div>
              <div className="border-t border-dashed border-gray-300 my-2"></div>
              <div className="flex justify-between text-slate-800 text-xl font-bold">
                <span>Total Geral:</span>
                <span>{formatCurrency(total)}</span>
              </div>
            </div>
          </div>
        </section>

        {/* FOOTER FIXO */}
        <footer className="p-8 border-t border-gray-100 text-center text-xs text-gray-400 uppercase tracking-widest">
          Obrigado pela preferência • {COMPANY_INFO.website}
        </footer>
      </div>

      {/* AÇÕES NO-PRINT */}
      <div className="max-w-5xl mx-auto mt-8 flex flex-wrap gap-4 justify-center no-print">
        <button
          onClick={() => window.scrollTo({ top: 0, behavior: 'smooth' })}
          className="flex items-center space-x-2 bg-white border border-gray-300 hover:bg-gray-50 text-gray-700 px-6 py-3 rounded-xl shadow-sm transition-all font-medium"
        >
          <Eye className="w-5 h-5" />
          <span>Visualizar</span>
        </button>
        <button
          onClick={handlePrint}
          className="flex items-center space-x-2 bg-slate-800 hover:bg-slate-900 text-white px-8 py-3 rounded-xl shadow-lg transition-all font-bold"
        >
          <Printer className="w-5 h-5" />
          <span>Imprimir Orçamento</span>
        </button>
        <button
          onClick={handlePrint}
          className="flex items-center space-x-2 bg-blue-600 hover:bg-blue-700 text-white px-8 py-3 rounded-xl shadow-lg transition-all font-bold"
        >
          <Download className="w-5 h-5" />
          <span>Exportar PDF</span>
        </button>
      </div>

      {/* ESPAÇAMENTO RODAPÉ IMPRESSÃO */}
      <div className="h-12 no-print"></div>
    </div>
  );
};

export default App;

export interface ClientData {
  name: string;
  address: string;
  city: string;
  uf: string;
  phone: string;
  cep: string;
  cpfCnpj: string;
