  name: string;
  address: string;
  cep: string;
  city: string;
  cnpj: string;
  phone: string;
}

import { CompanyInfo } from './types';

export const COMPANY_INFO: CompanyInfo = {
  name: "CASA DOS VIDROS",
  address: "Rua Antônio Carlos Pompeu, 113 - Pq Ns Senhora Dores",
  cep: "13 483 057",
  city: "Limeira, SP",
  cnpj: "59.744.237/0001-20",
