import React, { useState, useMemo } from 'react';
import { Plus, Trash2, Printer, Download, Image as ImageIcon, Briefcase } from 'lucide-react';
import { ClientData, QuoteItem } from './types';
import { COMPANY_INFO, DEFAULT_ITEM_NOTES } from './constants';

const App: React.FC = () => {
  const [clientData, setClientData] = useState<ClientData>({
    name: 'Associação pais e mestre Colégio técnico',
    address: 'Rua: Paschoal Marmo, n° 1.888',
    city: 'LIMEIRA',
    uf: 'SP',
    phone: '',
    cep: '13.484.332',
    cpfCnpj: '60.729.894/0001-87',
    rgIe: '',
    email: 'Controladoria @slmandic.edu.br',
    obs: '',
    date: '29/09/2025',
    quoteNumber: '577',
  });

  const [quoteInfo, setQuoteInfo] = useState({
    color: 'Vidro incolor, alumínio branco',
    generalInfo: ''
  });

  const [items, setItems] = useState<QuoteItem[]>([
    { 
      id: '1', 
      description: 'Porta Sala Podcast.\nPorta retrátil 1Fixo 2Corres com bandeira.\nVidro incolor 08mm alumínio branco 3000 x 2640', 
      quantity: 1, 
      unitPrice: 3790.00,
      notes: DEFAULT_ITEM_NOTES
    }
  ]);

  const subtotal = useMemo(() => {
    return items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  }, [items]);

  const handleClientChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setClientData(prev => ({ ...prev, [name]: value }));
  };

  const addItem = () => {
    setItems(prev => [
      ...prev,
      { id: Math.random().toString(36).substr(2, 9), description: '', quantity: 1, unitPrice: 0, notes: DEFAULT_ITEM_NOTES }
    ]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) setItems(prev => prev.filter(item => item.id !== id));
  };

  const updateItem = (id: string, field: keyof QuoteItem, value: any) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const handleImageUpload = (id: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => updateItem(id, 'image', reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const formatCurrency = (value: number) => {
    return new Intl.NumberFormat('pt-BR', { minimumFractionDigits: 2 }).format(value);
  };

  return (
    <div className="min-h-screen bg-gray-100 py-4 sm:py-8 print:p-0">
      <div className="max-w-[1000px] mx-auto bg-white shadow-lg p-6 sm:p-10 border border-gray-300 print:shadow-none print:border-none" id="quote-container">

        {/* TOP HEADER */}
        <div className="flex flex-col md:flex-row gap-6 mb-4 items-start border-b border-black pb-4">
          <div className="flex-1 flex gap-4 items-center">
             <div className="w-48 h-24 bg-slate-900 flex items-center justify-center rounded text-white overflow-hidden p-2">
                <div className="text-center">
                  <Briefcase className="w-8 h-8 mx-auto mb-1 text-blue-400" />
                  <div className="text-xs font-bold leading-tight">Casa dos <br/> <span className="text-lg tracking-widest">Vidros</span></div>
                  <div className="text-[8px] opacity-70">VIDRAÇARIA</div>
                </div>
             </div>
             <div className="text-[11px] leading-tight text-gray-800">
               <h1 className="text-sm font-bold mb-1">{COMPANY_INFO.name}</h1>
               <p>{COMPANY_INFO.address}</p>
               <p>CEP {COMPANY_INFO.cep}</p>
               <p>{COMPANY_INFO.city}</p>
               <p>CNPJ {COMPANY_INFO.cnpj}</p>
               <p>CEL: {COMPANY_INFO.phone}</p>
             </div>
          </div>
          <div className="w-full md:w-56 flex flex-col gap-1">
             <div className="bg-gray-500 text-white text-center py-1 font-bold tracking-widest text-sm">PEDIDO</div>
             <div className="bg-gray-200 text-center py-1 font-bold text-sm border border-gray-300">{clientData.quoteNumber}</div>
             <div className="bg-gray-200 text-center py-1 text-sm border border-gray-300">{clientData.date}</div>
          </div>
        </div>

        {/* INFORMAÇÕES DO CLIENTE */}
        <div className="mb-4">
          <div className="bg-gray-200 border-b border-gray-400 px-2 py-0.5 text-[11px] font-bold uppercase">Informações do Cliente</div>
          <div className="grid grid-cols-12 border-x border-b border-gray-300 text-[11px]">
            <div className="col-span-8 flex border-b border-gray-200">
              <span className="p-1 font-bold w-12 border-r border-gray-200">Nome</span>
              <input name="name" value={clientData.name} onChange={handleClientChange} className="flex-1 p-1 outline-none font-medium" />
            </div>
            <div className="col-span-4 flex border-b border-gray-200">
              <span className="p-1 font-bold w-16 border-r border-gray-200">Endereço</span>
              <input name="address" value={clientData.address} onChange={handleClientChange} className="flex-1 p-1 outline-none" />
            </div>
            <div className="col-span-3 flex border-b border-gray-200">
              <span className="p-1 font-bold w-12 border-r border-gray-200">Cidade</span>
              <input name="city" value={clientData.city} onChange={handleClientChange} className="flex-1 p-1 outline-none" />
            </div>
            <div className="col-span-1 flex border-b border-gray-200">
              <span className="p-1 font-bold w-8 border-r border-gray-200">UF</span>
              <input name="uf" value={clientData.uf} onChange={handleClientChange} className="flex-1 p-1 outline-none text-center" />
            </div>
            <div className="col-span-3 flex border-b border-gray-200">
              <span className="p-1 font-bold w-16 border-r border-gray-200">Telefone</span>
              <input name="phone" value={clientData.phone} onChange={handleClientChange} className="flex-1 p-1 outline-none" />
            </div>
            <div className="col-span-5 flex border-b border-gray-200 border-l border-gray-200">
              <span className="p-1 font-bold border-r border-gray-200">CEP</span>
              <input name="cep" value={clientData.cep} onChange={handleClientChange} className="flex-1 p-1 outline-none" />
              <span className="p-1 font-bold border-x border-gray-200">CPF/CNPJ</span>
              <input name="cpfCnpj" value={clientData.cpfCnpj} onChange={handleClientChange} className="flex-1 p-1 outline-none" />
              <span className="p-1 font-bold border-x border-gray-200">RG / IE</span>
