import React, { useState, useMemo, useRef } from 'react';
import { Plus, Trash2, Printer, Image as ImageIcon, User, FileText, Info, MessageCircle, Camera, Upload } from 'lucide-react';
import { ClientData, QuoteItem } from './types';
import { COMPANY_INFO, DEFAULT_OBSERVATIONS } from './constants';

// Componente Logo com suporte a edição manual
const EditableLogo = ({ src, onLogoChange }: { src: string | null, onLogoChange: (newSrc: string) => void }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onLogoChange(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  // URL padrão baseada na imagem enviada pelo usuário (simulada)
  const defaultLogo = "https://raw.githubusercontent.com/stackblitz/stackblitz-images/main/casa-dos-vidros-logo.png";
  const displaySrc = src || defaultLogo;

  return (
    <div className="relative group cursor-pointer no-print-logo-edit">
      <div 
        onClick={handleClick}
        className="relative w-32 h-32 md:w-44 md:h-44 rounded-full overflow-hidden shadow-[0_10px_40px_rgba(0,0,0,0.3)] border-4 border-slate-700 bg-[#002137] flex items-center justify-center transition-all hover:scale-105 hover:border-blue-500 duration-300"
      >
        <img 
          src={displaySrc} 
          alt="Logo Empresa" 
          className="w-full h-full object-cover"
          onError={(e) => {
            e.currentTarget.style.display = 'none';
            const parent = e.currentTarget.parentElement;
            if (parent) {
              parent.innerHTML = `
                <div class="flex flex-col items-center justify-center text-white p-4">
                  <span class="text-[10px] font-bold opacity-70">CASA DOS</span>
                  <span class="text-xl font-black tracking-tight">VIDROS</span>
                  <div class="w-8 h-1 bg-blue-500 mt-1"></div>
                </div>
              `;
            }
          }}
        />

        {/* Overlay de edição (visível apenas ao passar o mouse, e não sai no print) */}
        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center no-print">
          <Upload className="text-white w-8 h-8 mb-1" />
          <span className="text-white text-[10px] font-black uppercase tracking-widest">Alterar Logo</span>
        </div>
      </div>
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        accept="image/*" 
        className="hidden" 
      />
    </div>
  );
};

const App: React.FC = () => {
  const [companyLogo, setCompanyLogo] = useState<string | null>(null);
  const [clientData, setClientData] = useState<ClientData>({
    name: 'Associação pais e mestre Colégio técnico',
    address: 'Rua: Paschoal Marmo, n° 1.888',
    city: 'LIMEIRA',
    uf: 'SP',
    phone: '',
    cep: '13.484.332',
    cpfCnpj: '60.729.894/0001-87',
    rgIe: '',
    email: 'Controladoria @slmandic.edu.br',
    obs: '',
    date: new Date().toLocaleDateString('pt-BR'),
    quoteNumber: '577',
  });

  const [budgetInfo, setBudgetInfo] = useState({
    color: 'Vidro incolor, alumínio branco',
    info: ''
  });

  const [items, setItems] = useState<QuoteItem[]>([
    { 
      id: '1', 
      description: 'Porta Sala Podcast. Porta retrátil 1Fixo 2Corres com bandeira. Vidro incolor 08mm alumínio branco 3000 x 2640', 
      quantity: 1, 
      unitPrice: 3790.00 
    }
  ]);

  const [observations, setObservations] = useState(DEFAULT_OBSERVATIONS);

  const subtotal = useMemo(() => {
    return items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0);
  }, [items]);

  const total = subtotal;

  const handleClientChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setClientData(prev => ({ ...prev, [name]: value }));
  };

  const addItem = () => {
    setItems(prev => [
      ...prev,
      { id: Math.random().toString(36).substr(2, 9), description: '', quantity: 1, unitPrice: 0 }
    ]);
  };

  const removeItem = (id: string) => {
    if (items.length > 1) {
      setItems(prev => prev.filter(item => item.id !== id));
    }
  };

  const updateItem = (id: string, field: keyof QuoteItem, value: any) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, [field]: value } : item));
