          <div className="flex flex-col md:flex-row items-center gap-8 relative z-10 text-center md:text-left">
            <EditableLogo src={companyLogo} onLogoChange={setCompanyLogo} />
            <div>
              <h1 className="text-3xl font-black tracking-tighter uppercase mb-2 bg-gradient-to-r from-white to-slate-400 bg-clip-text text-transparent">
                {COMPANY_INFO.name}
              </h1>
              <p className="text-slate-400 text-sm font-medium uppercase tracking-wider max-w-xs leading-tight">
                {COMPANY_INFO.address}
              </p>
              <div className="flex flex-wrap justify-center md:justify-start gap-x-4 gap-y-1 mt-4 text-[11px] text-slate-500 font-bold uppercase tracking-widest">
                <span className="flex items-center gap-1"><span className="w-1.5 h-1.5 bg-blue-500 rounded-full"></span> CNPJ: {COMPANY_INFO.cnpj}</span>
                <span className="flex items-center gap-1"><span className="w-1.5 h-1.5 bg-blue-500 rounded-full"></span> {COMPANY_INFO.city}</span>
              </div>
            </div>
          </div>

          <div className="relative z-10">
            <div className="bg-white/5 backdrop-blur-md p-5 rounded-2xl border border-white/10 shadow-inner group transition-all hover:bg-white/10">
              <p className="text-blue-400 text-[10px] font-black uppercase tracking-[0.3em] mb-2">WhatsApp de Vendas</p>
              <p className="text-2xl font-black tracking-tighter group-hover:text-blue-300 transition-colors">{COMPANY_INFO.phone}</p>
            </div>
          </div>
        </header>

        {/* INFORMAÇÕES DO CLIENTE */}
        <section className="p-8 md:p-12 bg-white">
          <div className="flex items-center space-x-4 mb-10">
            <div className="p-2 bg-blue-50 rounded-lg">
              <User className="w-6 h-6 text-blue-600" />
            </div>
            <h2 className="text-xl font-black uppercase tracking-widest text-slate-800">Dados do Cliente</h2>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
            <div className="md:col-span-2">
              <label className="block text-[11px] font-black text-slate-400 uppercase tracking-widest mb-2 ml-1">Cliente / Razão Social</label>
              <input type="text" name="name" value={clientData.name} onChange={handleClientChange} className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-semibold text-slate-700 transition-all hover:border-slate-300" />
            </div>
