// Componente Logo com suporte a edição manual
const EditableLogo = ({ src, onLogoChange }: { src: string | null, onLogoChange: (newSrc: string) => void }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onLogoChange(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const defaultLogo = "https://raw.githubusercontent.com/stackblitz/stackblitz-images/main/casa-dos-vidros-logo.png";
  const displaySrc = src || defaultLogo;

  return (
    <div className="relative group cursor-pointer no-print-logo-edit shrink-0">
      <div 
        onClick={handleClick}
        className="relative w-24 h-24 md:w-36 md:h-36 rounded-full overflow-hidden shadow-[0_10px_40px_rgba(0,0,0,0.3)] border-4 border-slate-700 bg-[#002137] flex items-center justify-center transition-all hover:scale-105 hover:border-blue-500 duration-300"
      >
        <img 
          src={displaySrc} 
          alt="Logo Empresa" 
          className="w-full h-full object-cover"
          onError={(e) => {
            e.currentTarget.style.display = 'none';
            const parent = e.currentTarget.parentElement;
            if (parent) {
              parent.innerHTML = `
                <div class="flex flex-col items-center justify-center text-white p-4">
                  <span class="text-[8px] font-bold opacity-70 uppercase tracking-tighter">CASA DOS</span>
                  <span class="text-lg font-black tracking-tighter">VIDROS</span>
                </div>
              `;
            }
          }}
        />
        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center no-print">
          <Upload className="text-white w-6 h-6 mb-1" />
          <span className="text-white text-[8px] font-black uppercase tracking-widest">Alterar</span>
        </div>
      </div>
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        accept="image/*" 
        className="hidden" 
      />
    </div>
  );
};

