const EditableLogo = ({ src, onLogoChange }: { src: string | null, onLogoChange: (newSrc: string) => void }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const handleClick = () => fileInputRef.current?.click();
  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => onLogoChange(reader.result as string);
      reader.readAsDataURL(file);
    }
  };
  const defaultLogo = "https://raw.githubusercontent.com/stackblitz/stackblitz-images/main/casa-dos-vidros-logo.png";
  const displaySrc = src || defaultLogo;

  return (
    <div className="relative group cursor-pointer no-print-logo-edit shrink-0">
      <div 
        onClick={handleClick}
        className="relative w-20 h-20 md:w-28 md:h-28 rounded-full overflow-hidden shadow-lg border-2 border-slate-700 bg-[#002137] flex items-center justify-center transition-all hover:scale-105"
      >
        <img src={displaySrc} alt="Logo" className="w-full h-full object-cover" />
        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center no-print">
          <Upload className="text-white w-5 h-5" />
        </div>
      </div>
      <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
    </div>
  );
};

