  const [isSharing, setIsSharing] = useState(false);

  const handleShareQuoteAsImage = async () => {
    const element = document.getElementById('quote-container');
    if (!element) return;

    setIsSharing(true);
    try {
      // Pequeno delay para garantir que o renderizador do navegador processe as últimas alterações
      await new Promise(r => setTimeout(r, 100));

      const canvas = await (window as any).html2canvas(element, {
        scale: 2, // Maior qualidade
        useCORS: true,
        logging: false,
        backgroundColor: '#ffffff',
        // Ocultar botões no print/foto caso não estejam na div correta
        onclone: (clonedDoc: Document) => {
          const noPrintElements = clonedDoc.querySelectorAll('.no-print');
          noPrintElements.forEach(el => (el as HTMLElement).style.display = 'none');
        }
      });

      canvas.toBlob(async (blob: Blob | null) => {
        if (!blob) throw new Error("Falha ao gerar imagem");

        const fileName = `Orcamento_${clientData.quoteNumber}_${clientData.name.replace(/\s+/g, '_')}.png`;
        const file = new File([blob], fileName, { type: 'image/png' });

        // Tentar usar Web Share API (Nativo em Celulares)
        if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
          await navigator.share({
            files: [file],
            title: `Orçamento ${clientData.quoteNumber}`,
            text: `Segue orçamento da Casa dos Vidros para ${clientData.name}. Total: ${formatCurrency(total)}`,
          });
        } else {
          // Fallback: Download e abrir WhatsApp com o texto
          const url = URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.download = fileName;
          link.click();
          URL.revokeObjectURL(url);

