          window.open(`https://wa.me/?text=${encodeURIComponent(message)}`, '_blank');
        }
      }, 'image/png');

    } catch (err) {
      console.error("Erro ao compartilhar:", err);
      alert("Houve um erro ao gerar a foto do orçamento. Tente novamente.");
