                </div>

                <div className="flex-1 flex flex-col justify-between">
                  <textarea 
                    value={item.description} 
                    onChange={(e) => updateItem(item.id, 'description', e.target.value)} 
                    rows={2} 
                    className="w-full bg-transparent p-0 border-none text-[10px] font-bold text-slate-800 leading-tight resize-none outline-none mb-2" 
                    placeholder="Especifique o serviço ou produto..." 
                  />

                  <div className="flex items-end justify-between gap-4">
                    <div className="flex gap-4">
                      <div className="w-14">
                        <label className="block text-[7px] font-black text-slate-400 uppercase mb-0.5">Qtd</label>
                        <input type="number" min="1" value={item.quantity} onChange={(e) => updateItem(item.id, 'quantity', Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded-lg p-1 text-[11px] font-black text-center" />
                      </div>
                      <div className="w-32">
                        <label className="block text-[7px] font-black text-slate-400 uppercase mb-0.5">Valor Unitário</label>
                        <div className="flex items-center bg-slate-50 rounded-lg px-2 border border-slate-100 h-8">
                          <span className="text-[8px] text-slate-400 mr-1.5 font-black">R$</span>
                          <input type="number" step="0.01" value={item.unitPrice} onChange={(e) => updateItem(item.id, 'unitPrice', Number(e.target.value))} className="w-full bg-transparent border-none p-0 text-[11px] font-black outline-none" />
