                      </div>
                    </div>
                    <div className="text-right">
                      <label className="block text-[7px] font-black text-slate-400 uppercase mb-0.5">Total Item</label>
                      <span className="text-[12px] font-black text-slate-900">{formatCurrency(item.quantity * item.unitPrice)}</span>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* RODAPÉ */}
        <section className="p-4 md:p-6 bg-slate-50 border-t border-slate-100 flex flex-col md:flex-row gap-6 items-start">
          <div className="flex-1 w-full">
            <h3 className="text-[9px] font-black uppercase tracking-widest text-slate-500 mb-2">Observações Importantes</h3>
            <textarea 
              rows={5} 
              value={observations} 
              onChange={(e) => setObservations(e.target.value)} 
              className="w-full bg-white p-3 border border-slate-200 rounded-xl text-[10px] text-slate-600 outline-none leading-relaxed resize-none shadow-sm print:h-auto" 
            />
          </div>

          <div className="w-full md:w-56 flex flex-col justify-center">
            <div className="bg-[#002137] p-4 rounded-2xl shadow-xl relative overflow-hidden group border border-white/5">
              <span className="text-blue-300 text-[8px] font-black uppercase tracking-widest mb-1 block leading-none">VALOR TOTAL ESTIMADO</span>
              <span className="text-white text-xl md:text-2xl font-black tracking-tighter block leading-none py-1">
                {formatCurrency(total)}
              </span>
              <div className="mt-3 pt-3 border-t border-white/10">
                <p className="text-[8px] font-black text-blue-200 italic uppercase leading-tight">
                  Sujeito a alteração após medição final.
                </p>
              </div>
            </div>
            <p className="mt-3 text-[7px] text-slate-400 text-center uppercase font-black tracking-widest leading-none">
              Validade: 15 dias • Qualidade Casa dos Vidros
            </p>
          </div>
        </section>

        <footer className="py-2.5 text-center border-t border-slate-50 bg-white">
          <p className="text-[8px] font-black text-slate-300 uppercase tracking-[0.4em]">
            © 2025 • ORÇAMENTO DIGITAL • {COMPANY_INFO.name}
          </p>
        </footer>
      </div>

      {/* AÇÕES FIXAS - FORA DO CONTAINER DE CAPTURA */}
      <div className="max-w-4xl mx-auto mt-6 flex flex-wrap gap-4 justify-center no-print pb-16 px-4">
        <button 
          onClick={() => window.print()} 
          className="flex-1 min-w-[140px] flex items-center justify-center gap-2 bg-[#002137] hover:bg-black text-white px-5 py-3 rounded-xl shadow-lg transition-all font-black uppercase tracking-widest text-[10px] active:scale-95"
        >
          <Printer className="w-4 h-4" /> PDF / Imprimir
        </button>

        <button 
          onClick={handleShareQuoteAsImage} 
          disabled={isSharing}
          className={`flex-1 min-w-[140px] flex items-center justify-center gap-2 ${isSharing ? 'bg-slate-400 cursor-wait' : 'bg-[#25D366] hover:bg-[#128C7E]'} text-white px-5 py-3 rounded-xl shadow-lg transition-all font-black uppercase tracking-widest text-[10px] active:scale-95`}
        >
          {isSharing ? (
            <span className="flex items-center gap-2 animate-pulse">Gerando Foto...</span>
          ) : (
            <>
              <Share2 className="w-4 h-4" /> Enviar Foto (WhatsApp)
            </>
          )}
        </button>
      </div>
    </div>
  );
};

export default App;

