              <stop offset="0%" stopColor="#6ea8fe" />
              <stop offset="100%" stopColor="#0d6efd" />
            </linearGradient>
          </defs>
          <g transform="translate(60, 130) scale(0.9)">
            <rect x="0" y="0" width="80" height="140" fill="url(#glassGrad)" opacity="0.9" transform="skewY(-15)" />
            <rect x="25" y="10" width="80" height="140" fill="url(#glassGrad)" opacity="0.7" transform="skewY(-15)" />
            <rect x="50" y="20" width="80" height="140" fill="url(#glassGrad)" opacity="0.5" transform="skewY(-15)" />
          </g>
          <g transform="translate(160, 160)">
            <path d="M10,0 L140,0 L180,45 L140,90 L10,90 Z" fill="none" stroke="white" strokeWidth="6" strokeLinejoin="round" />
            <text x="15" y="38" fontFamily="Arial, sans-serif" fontWeight="900" fontSize="32" fill="white">Casa dos</text>
            <text x="15" y="75" fontFamily="Arial, sans-serif" fontWeight="900" fontSize="48" fill="white">Vidros</text>
            <text x="55" y="105" fontFamily="Arial, sans-serif" fontWeight="bold" fontSize="14" fill="white" letterSpacing="2">VIDRAÇARIA</text>
          </g>
        </svg>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const today = new Date().toLocaleDateString('pt-BR');

  const [clientData, setClientData] = useState<ClientData>({
    name: 'Associação pais e mestre Colégio técnico',
    address: 'Rua: Paschoal Marmo, n° 1.888',
    city: 'LIMEIRA',
    uf: 'SP',
    phone: '',
    cep: '13.484.332',
    cpfCnpj: '60.729.894/0001-87',
    rgIe: '',
    email: 'Controladoria @slmandic.edu.br',
    obs: '',
    date: today,
    quoteNumber: '577',
  });

  const [budgetInfo, setBudgetInfo] = useState({
    color: 'Vidro incolor, alumínio branco',
    info: ''
  });

  const [items, setItems] = useState<QuoteItem[]>([
    { 
      id: '1', 
      description: 'Porta Sala Podcast. Porta retrátil 1Fixo 2Corres com bandeira. Vidro incolor 08mm alumínio branco 3000 x 2640', 
      quantity: 1, 
      unitPrice: 3790.00 
    }
  ]);

  const [observations, setObservations] = useState(DEFAULT_OBSERVATIONS);
  const total = useMemo(() => items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0), [items]);

  const handleClientChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setClientData(prev => ({ ...prev, [name]: value }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { id: Math.random().toString(36).substr(2, 9), description: '', quantity: 1, unitPrice: 0 }]);
  };

  const removeItem = (id: string) => items.length > 1 && setItems(prev => prev.filter(item => item.id !== id));

  const updateItem = (id: string, field: keyof QuoteItem, value: any) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const handleImageUpload = (id: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => updateItem(id, 'image', reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const formatCurrency = (value: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);

  const [isSharing, setIsSharing] = useState(false);

  const handleShareQuoteAsImage = async () => {
    const element = containerRef.current;
    if (!element) return;

    setIsSharing(true);
    try {
      window.scrollTo(0, 0);

      const canvas = await (window as any).html2canvas(element, {
        scale: 2.5,
        useCORS: true,
        allowTaint: true,
        backgroundColor: '#ffffff',
        logging: false,
        onclone: (clonedDoc: Document) => {
          const noPrint = clonedDoc.querySelectorAll('.no-print');
          noPrint.forEach(el => (el as HTMLElement).style.display = 'none');

          const container = clonedDoc.getElementById('quote-container');
          if (container) {
            container.style.boxShadow = 'none';
            container.style.border = 'none';
            container.style.borderRadius = '0';
            container.style.width = '1000px'; 
          }

          // Garantir que as colunas se mantenham lado a lado na captura
          const itemRows = clonedDoc.querySelectorAll('.item-row');
          itemRows.forEach(row => {
            (row as HTMLElement).style.display = 'flex';
            (row as HTMLElement).style.flexDirection = 'row';
          });

          const footerRows = clonedDoc.querySelectorAll('.footer-row');
          footerRows.forEach(row => {
            (row as HTMLElement).style.display = 'flex';
            (row as HTMLElement).style.flexDirection = 'row';
          });
        }
      });

      canvas.toBlob(async (blob: Blob | null) => {
        if (!blob) throw new Error("Falha ao gerar imagem");
        const fileName = `Orcamento_${clientData.quoteNumber}.png`;
        const file = new File([blob], fileName, { type: 'image/png' });

        if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
          await navigator.share({
            files: [file],
            title: `Orçamento ${clientData.quoteNumber}`,
          });
        } else {
