            (el as HTMLElement).style.display = 'flex';
            (el as HTMLElement).style.flexDirection = 'row';
          });

          const headers = clonedDoc.querySelectorAll('.header-info-container');
          headers.forEach(el => {
            (el as HTMLElement).style.display = 'flex';
            (el as HTMLElement).style.flexDirection = 'row';
          });

          const rightSides = clonedDoc.querySelectorAll('.header-right-side');
          rightSides.forEach(el => {
