            (el as HTMLElement).style.alignItems = 'flex-end';
            (el as HTMLElement).style.borderLeft = '1px solid rgba(255,255,255,0.1)';
            (el as HTMLElement).style.paddingLeft = '1.5rem';
          });
        }
      });

      canvas.toBlob(async (blob: Blob | null) => {
        if (!blob) throw new Error("Falha ao gerar imagem");
        const fileName = `Orcamento_${clientData.quoteNumber}.png`;
        const file = new File([blob], fileName, { type: 'image/png' });

        if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
          await navigator.share({
            files: [file],
            title: `Orçamento ${clientData.quoteNumber}`,
          });
        } else {
          const url = URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.download = fileName;
          link.click();
          URL.revokeObjectURL(url);
          alert("Imagem gerada e baixada!");
        }
      }, 'image/png');

