        </header>

        {/* DADOS CLIENTE */}
        <section className="p-4 md:p-6 bg-white border-b border-slate-100">
          <div className="flex items-center space-x-2 mb-4">
            <User className="w-4 h-4 text-[#002137]" />
            <h2 className="text-[11px] font-black uppercase tracking-widest text-slate-800">Dados do Cliente</h2>
          </div>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
            <div className="col-span-2">
              <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Nome / Razão Social</label>
              <input type="text" name="name" value={clientData.name} onChange={handleClientChange} className="w-full px-2.5 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[10px] font-bold text-slate-700 outline-none" />
            </div>
            <div>
              <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">CPF / CNPJ</label>
              <input type="text" name="cpfCnpj" value={clientData.cpfCnpj} onChange={handleClientChange} className="w-full px-2.5 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[10px] text-slate-600 outline-none" />
            </div>
            <div>
              <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">RG / IE</label>
              <input type="text" name="rgIe" value={clientData.rgIe} onChange={handleClientChange} className="w-full px-2.5 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[10px] text-slate-600 outline-none" />
            </div>
            <div className="col-span-2">
              <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Endereço Completo</label>
              <input type="text" name="address" value={clientData.address} onChange={handleClientChange} className="w-full px-2.5 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[10px] text-slate-600 outline-none" />
            </div>
            <div className="col-span-2">
              <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">E-mail</label>
              <input type="email" name="email" value={clientData.email} onChange={handleClientChange} className="w-full px-2.5 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[10px] text-slate-600 outline-none" />
            </div>
          </div>
        </section>

        {/* INFO ADICIONAL */}
        <section className="px-4 md:px-6 py-3 bg-slate-50 border-b border-slate-100 grid grid-cols-2 gap-4">
          <div className="flex items-center gap-3">
            <Info className="w-4 h-4 text-blue-600 shrink-0" />
            <div className="flex-1">
              <label className="block text-[8px] font-black text-slate-400 uppercase mb-0.5 tracking-tight">Acabamento</label>
              <input type="text" value={budgetInfo.color} onChange={(e) => setBudgetInfo(p => ({...p, color: e.target.value}))} className="w-full bg-transparent border-none p-0 text-[10px] font-black text-slate-800 outline-none" />
            </div>
          </div>
          <div className="flex items-center gap-3">
            <Hash className="w-4 h-4 text-blue-600 shrink-0" />
            <div className="flex-1">
              <label className="block text-[8px] font-black text-slate-400 uppercase mb-0.5 tracking-tight">Nota Técnica</label>
              <input type="text" value={budgetInfo.info} onChange={(e) => setBudgetInfo(p => ({...p, info: e.target.value}))} className="w-full bg-transparent border-none p-0 text-[10px] font-black text-slate-800 outline-none" placeholder="Ex: Vidro 10mm" />
            </div>
          </div>
        </section>

        {/* ITENS */}
        <section className="p-4 md:p-6 min-h-[250px]">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center space-x-2">
              <FileText className="w-4 h-4 text-slate-700" />
              <h2 className="text-[11px] font-black uppercase tracking-widest text-slate-800">Descrição do Orçamento</h2>
            </div>
            <button onClick={addItem} className="no-print flex items-center gap-1.5 bg-[#002137] text-white px-3 py-1.5 rounded-lg text-[10px] font-black uppercase shadow-md active:scale-95 transition-colors">
              <Plus className="w-3.5 h-3.5" /> Adicionar Item
            </button>
          </div>

          <div className="space-y-4">
            {items.map((item) => (
              <div key={item.id} className="item-row flex flex-row items-start gap-4 border border-slate-100 rounded-xl p-3 bg-white relative group">
                <button onClick={() => removeItem(item.id)} className="absolute -top-2 -right-2 no-print text-white bg-red-500 p-1.5 rounded-full shadow-lg opacity-0 group-hover:opacity-100 z-10 transition-opacity">
                  <Trash2 className="w-3.5 h-3.5" />
                </button>

                <div className="w-24 h-24 shrink-0 border-2 border-dashed border-slate-200 rounded-xl flex items-center justify-center overflow-hidden bg-slate-50 relative">
                  {item.image ? (
                    <img src={item.image} alt="Produto" className="w-full h-full object-cover" />
                  ) : (
                    <ImageIcon className="text-slate-300 w-6 h-6" />
                  )}
                  <input type="file" accept="image/*" onChange={(e) => handleImageUpload(item.id, e)} className="absolute inset-0 opacity-0 cursor-pointer no-print" />
                </div>

                <div className="flex-1 flex flex-col justify-between h-24">
                  <textarea 
                    value={item.description} 
                    onChange={(e) => updateItem(item.id, 'description', e.target.value)} 
                    className="w-full bg-transparent p-0 border-none text-[10px] font-bold text-slate-800 leading-tight resize-none outline-none" 
                    placeholder="Descrição do item..." 
                  />

                  <div className="flex items-end justify-between">
                    <div className="flex gap-4">
                      <div className="w-12">
                        <label className="block text-[7px] font-black text-slate-400 uppercase mb-0.5">Qtd</label>
                        <input type="number" min="1" value={item.quantity} onChange={(e) => updateItem(item.id, 'quantity', Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded p-0.5 text-[11px] font-black text-center" />
                      </div>
                      <div className="w-28">
                        <label className="block text-[7px] font-black text-slate-400 uppercase mb-0.5">Valor Unitário</label>
                        <div className="flex items-center bg-slate-50 rounded px-1.5 border border-slate-100 h-8">
                          <span className="text-[8px] text-slate-400 font-black mr-1">R$</span>
                          <input type="number" step="0.01" value={item.unitPrice} onChange={(e) => updateItem(item.id, 'unitPrice', Number(e.target.value))} className="w-full bg-transparent border-none py-1 text-[11px] font-black outline-none" />
                        </div>
                      </div>
                    </div>
                    <div className="text-right">
                      <label className="block text-[7px] font-black text-slate-400 uppercase mb-0.5">Total Item</label>
                      <span className="text-[12px] font-black text-slate-900">{formatCurrency(item.quantity * item.unitPrice)}</span>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* RODAPÉ */}
        <section className="p-4 md:p-6 bg-slate-50 border-t border-slate-100 flex flex-row items-start gap-6 footer-row">
          <div className="flex-1">
            <h3 className="text-[9px] font-black uppercase tracking-widest text-slate-500 mb-2">Observações Importantes</h3>
            <textarea 
              rows={5} 
              value={observations} 
              onChange={(e) => setObservations(e.target.value)} 
              className="w-full bg-white p-3 border border-slate-200 rounded-xl text-[10px] text-slate-600 outline-none leading-relaxed resize-none shadow-sm h-full min-h-[100px]" 
            />
          </div>

          <div className="w-64 shrink-0">
            <div className="bg-[#002137] p-4 rounded-2xl shadow-xl relative overflow-hidden border border-white/5">
              <span className="text-blue-300 text-[8px] font-black uppercase tracking-widest mb-1 block leading-none">VALOR TOTAL PROJETO</span>
              <span className="text-white text-2xl font-black tracking-tighter block leading-none py-1">
                {formatCurrency(total)}
              </span>
              <div className="mt-3 pt-3 border-t border-white/10">
                <p className="text-[8px] font-black text-blue-200 italic uppercase leading-tight">
                  Sujeito a alteração após medição.
                </p>
              </div>
            </div>
            <p className="mt-3 text-[7px] text-slate-400 text-center uppercase font-black tracking-widest leading-none">
              Validade do Orçamento: 15 dias • Casa dos Vidros
            </p>
          </div>
        </section>

        <footer className="py-2.5 text-center border-t border-slate-50 bg-white">
          <p className="text-[8px] font-black text-slate-300 uppercase tracking-[0.4em]">
            © 2025 • ORÇAMENTO DIGITAL • {COMPANY_INFO.name}
          </p>
        </footer>
      </div>

      {/* AÇÕES */}
      <div className="max-w-4xl mx-auto mt-6 flex flex-row gap-4 justify-center no-print pb-16 px-4">
        <button 
          onClick={() => window.print()} 
          className="flex-1 max-w-[220px] flex items-center justify-center gap-2 bg-[#002137] text-white px-5 py-3.5 rounded-xl shadow-lg font-black uppercase text-[10px] active:scale-95 transition-all hover:bg-black"
        >
          <Printer className="w-4 h-4" /> Gerar PDF / Imprimir
        </button>

        <button 
          onClick={handleShareQuoteAsImage} 
          disabled={isSharing}
          className={`flex-1 max-w-[220px] flex items-center justify-center gap-2 ${isSharing ? 'bg-slate-400' : 'bg-[#25D366] hover:bg-[#128C7E]'} text-white px-5 py-3.5 rounded-xl shadow-lg font-black uppercase text-[10px] active:scale-95 transition-all`}
        >
          <Share2 className="w-4 h-4" /> {isSharing ? "Gerando Imagem..." : "Enviar como Foto"}
        </button>
      </div>
    </div>
  );
};

export default App;

export interface ClientData {
  name: string;
  address: string;
  city: string;
  uf: string;
  phone: string;
  cep: string;
  cpfCnpj: string;
  rgIe: string;
  email: string;
  obs: string;
  date: string;
  quoteNumber: string;
}

export interface QuoteItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
  image?: string;
  notes?: string;
}

export interface CompanyInfo {
  name: string;
  owner: string;
  address: string;
  cep: string;
  city: string;
  cnpj: string;
  phone: string;
}

export interface SavedQuote {
  id: string;
  timestamp: number;
  clientData: ClientData;
  items: QuoteItem[];
  budgetInfo: {
    color: string;
    info: string;
  };
  observations: string;
}

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Plus, Trash2, Printer, Image as ImageIcon, User, FileText, Info, MessageCircle, Hash, Share2, Save, History, RotateCcw, Download } from 'lucide-react';
import { ClientData, QuoteItem, SavedQuote } from './types';
import { COMPANY_INFO, DEFAULT_OBSERVATIONS } from './constants';

const CompanyLogo = () => {
  return (
    <div className="relative shrink-0">
      <div className="relative w-16 h-16 md:w-24 md:h-24 rounded-full overflow-hidden shadow-lg border-2 border-white/10 bg-[#002137] flex items-center justify-center">
        <svg viewBox="0 0 400 400" className="w-full h-full p-2">
          <circle cx="200" cy="200" r="190" fill="#002137" />
          <defs>
            <linearGradient id="glassGrad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#6ea8fe" />
              <stop offset="100%" stopColor="#0d6efd" />
            </linearGradient>
          </defs>
          <g transform="translate(60, 130) scale(0.9)">
            <rect x="0" y="0" width="80" height="140" fill="url(#glassGrad)" opacity="0.9" transform="skewY(-15)" />
            <rect x="25" y="10" width="80" height="140" fill="url(#glassGrad)" opacity="0.7" transform="skewY(-15)" />
            <rect x="50" y="20" width="80" height="140" fill="url(#glassGrad)" opacity="0.5" transform="skewY(-15)" />
          </g>
          <g transform="translate(160, 160)">
            <path d="M10,0 L140,0 L180,45 L140,90 L10,90 Z" fill="none" stroke="white" strokeWidth="6" strokeLinejoin="round" />
            <text x="15" y="38" fontFamily="Arial, sans-serif" fontWeight="900" fontSize="32" fill="white">Casa dos</text>
            <text x="15" y="75" fontFamily="Arial, sans-serif" fontWeight="900" fontSize="48" fill="white">Vidros</text>
            <text x="55" y="105" fontFamily="Arial, sans-serif" fontWeight="bold" fontSize="14" fill="white" letterSpacing="2">VIDRAÇARIA</text>
          </g>
        </svg>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const today = new Date().toLocaleDateString('pt-BR');

  // Estados principais
  const [clientData, setClientData] = useState<ClientData>({
    name: '',
    address: '',
    city: 'LIMEIRA',
    uf: 'SP',
    phone: '',
    cep: '',
    cpfCnpj: '',
    rgIe: '',
    email: '',
    obs: '',
    date: today,
    quoteNumber: '',
  });

  const [budgetInfo, setBudgetInfo] = useState({
    color: 'Vidro incolor, alumínio branco',
    info: ''
  });

  const [items, setItems] = useState<QuoteItem[]>([
    { id: '1', description: '', quantity: 1, unitPrice: 0 }
  ]);

  const [observations, setObservations] = useState(DEFAULT_OBSERVATIONS);
  const [savedQuotes, setSavedQuotes] = useState<SavedQuote[]>([]);
  const [isSharing, setIsSharing] = useState(false);

  // Carregar do "Banco de Dados" (LocalStorage) ao iniciar
  useEffect(() => {
    const data = localStorage.getItem('casa_dos_vidros_db');
    if (data) {
      setSavedQuotes(JSON.parse(data));
    }
  }, []);

  const total = useMemo(() => items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0), [items]);

  const handleClientChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setClientData(prev => ({ ...prev, [name]: value }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { id: Math.random().toString(36).substr(2, 9), description: '', quantity: 1, unitPrice: 0 }]);
  };

  const removeItem = (id: string) => items.length > 1 && setItems(prev => prev.filter(item => item.id !== id));

  const updateItem = (id: string, field: keyof QuoteItem, value: any) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const handleImageUpload = (id: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => updateItem(id, 'image', reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const formatCurrency = (value: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);

  // Funções do "Banco de Dados"
  const saveQuote = () => {
    if (!clientData.name || !clientData.quoteNumber) {
      alert("Por favor, preencha pelo menos o Nome do Cliente e o Nº do Orçamento.");
      return;
    }

    const newSavedQuote: SavedQuote = {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      clientData,
      items,
      budgetInfo,
      observations
    };

    const updated = [newSavedQuote, ...savedQuotes];
    setSavedQuotes(updated);
    localStorage.setItem('casa_dos_vidros_db', JSON.stringify(updated));
    alert("Orçamento salvo no histórico com sucesso!");
  };

  const loadQuote = (quote: SavedQuote) => {
    if (confirm("Deseja carregar este orçamento? Isso substituirá o que está na tela.")) {
      setClientData(quote.clientData);
      setItems(quote.items);
      setBudgetInfo(quote.budgetInfo);
      setObservations(quote.observations);
      window.scrollTo(0, 0);
    }
  };

  const deleteQuote = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Excluir este orçamento permanentemente?")) {
      const updated = savedQuotes.filter(q => q.id !== id);
      setSavedQuotes(updated);
      localStorage.setItem('casa_dos_vidros_db', JSON.stringify(updated));
    }
  };

  const newQuote = () => {
    if (confirm("Limpar tudo e iniciar um novo orçamento?")) {
      setClientData({ ...clientData, name: '', cpfCnpj: '', address: '', email: '', quoteNumber: '', date: today });
      setItems([{ id: '1', description: '', quantity: 1, unitPrice: 0 }]);
      setBudgetInfo({ color: 'Vidro incolor, alumínio branco', info: '' });
      setObservations(DEFAULT_OBSERVATIONS);
    }
  };

  const handleShareQuoteAsImage = async () => {
    const element = containerRef.current;
    if (!element) return;

    setIsSharing(true);
    try {
      window.scrollTo(0, 0);
      const canvas = await (window as any).html2canvas(element, {
        scale: 2.5,
        useCORS: true,
        allowTaint: true,
        backgroundColor: '#ffffff',
        logging: false,
        onclone: (clonedDoc: Document) => {
          const noPrint = clonedDoc.querySelectorAll('.no-print');
          noPrint.forEach(el => (el as HTMLElement).style.display = 'none');

          const container = clonedDoc.getElementById('quote-container');
          if (container) {
            container.style.boxShadow = 'none';
            container.style.border = 'none';
            container.style.borderRadius = '0';
            container.style.width = '1000px'; 
          }
          // Garante alinhamento forçado no clone
          const rightSide = clonedDoc.querySelector('.header-right-side') as HTMLElement;
          if (rightSide) {
             rightSide.style.display = 'flex';
             rightSide.style.flexDirection = 'column';
             rightSide.style.alignItems = 'flex-end';
             rightSide.style.textAlign = 'right';
          }
        }
      });

      canvas.toBlob(async (blob: Blob | null) => {
        if (!blob) throw new Error("Falha ao gerar imagem");
        const fileName = `Orcamento_${clientData.quoteNumber || 'Novo'}.png`;
        const file = new File([blob], fileName, { type: 'image/png' });

        if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
          await navigator.share({ files: [file], title: `Orçamento ${clientData.quoteNumber}` });
        } else {
          const url = URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.download = fileName;
          link.click();
          URL.revokeObjectURL(url);
        }
      }, 'image/png');
    } catch (err) {
      console.error(err);
      alert("Erro ao capturar orçamento.");
    } finally {
      setIsSharing(false);
    }
  };

  return (
    <div className="min-h-screen py-4 md:py-8 px-2 sm:px-4 bg-[#f1f5f9]">
      {/* BARRA DE AÇÕES SUPERIOR */}
      <div className="max-w-4xl mx-auto mb-6 flex justify-between items-center no-print">
         <div className="flex gap-2">
            <button onClick={newQuote} className="flex items-center gap-2 bg-white text-slate-700 px-4 py-2 rounded-xl shadow-sm border border-slate-200 font-bold text-[10px] uppercase hover:bg-slate-50 transition-all">
              <RotateCcw className="w-4 h-4 text-blue-500" /> Novo Orçamento
            </button>
            <button onClick={saveQuote} className="flex items-center gap-2 bg-[#002137] text-white px-4 py-2 rounded-xl shadow-md font-bold text-[10px] uppercase hover:bg-black transition-all">
              <Save className="w-4 h-4 text-blue-400" /> Salvar Orçamento
            </button>
         </div>
      </div>

      <div 
        ref={containerRef}
        id="quote-container" 
        className="max-w-4xl mx-auto bg-white shadow-2xl md:rounded-2xl overflow-hidden border border-slate-200 print:border-none print:shadow-none"
      >

        {/* CABEÇALHO */}
        <header className="bg-[#002137] text-white p-4 md:p-6 flex flex-row items-center gap-4 md:gap-6 relative header-info-container">
          <CompanyLogo />

          <div className="flex-1 flex flex-col justify-center text-left">
            <h1 className="text-xl md:text-2xl font-black tracking-tighter uppercase mb-0.5 bg-gradient-to-r from-white to-blue-100 bg-clip-text text-transparent leading-none">
              {COMPANY_INFO.name}
            </h1>
            <p className="text-slate-300 text-[10px] md:text-[11px] font-medium uppercase tracking-tight leading-tight mb-2">
              {COMPANY_INFO.address}
            </p>
            <div className="flex flex-col gap-1 text-[9px] text-slate-400 font-bold uppercase tracking-wider border-t border-white/5 pt-2">
              <span className="flex items-center gap-2">
                CNPJ: <span className="text-slate-200">{COMPANY_INFO.cnpj}</span> 
                <span className="text-slate-600">•</span> {COMPANY_INFO.city}
              </span>
              <div className="flex items-center gap-4">
                <span className="text-white font-extrabold flex items-center gap-1.5">
                  <User className="w-2.5 h-2.5 text-blue-400" /> {COMPANY_INFO.owner}
                </span>
                <span className="flex items-center gap-1.5 text-blue-300 font-extrabold">
                  <MessageCircle className="w-2.5 h-2.5" /> {COMPANY_INFO.phone}
                </span>
              </div>
            </div>
          </div>

          {/* ALINHAMENTO FIXO DIREITA */}
          <div className="flex flex-col items-end justify-center gap-2 shrink-0 border-l border-white/10 pl-6 h-full header-right-side min-w-[180px]">
            <div className="bg-blue-600/30 px-4 py-1.5 rounded-full border border-blue-400/30 text-blue-100 text-[10px] font-black uppercase tracking-[0.2em]">
              Orçamento
            </div>
            <div className="space-y-1 w-full text-right flex flex-col items-end">
              <div className="flex items-center justify-end gap-2 w-full">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-tighter shrink-0">DATA:</label>
                <input type="text" value={clientData.date} onChange={handleClientChange} name="date" className="bg-white/10 px-2 py-1 rounded border border-white/10 text-[11px] font-black text-center w-full max-w-[110px] outline-none text-white focus:border-blue-500/50" />
              </div>
              <div className="flex items-center justify-end gap-2 w-full">
                <label className="text-[9px] font-black text-slate-400 uppercase tracking-tighter shrink-0">Nº ORÇ:</label>
                <input type="text" value={clientData.quoteNumber} onChange={handleClientChange} name="quoteNumber" className="bg-white/10 px-2 py-1 rounded border border-white/10 text-[11px] font-black text-center w-full max-w-[80px] outline-none text-white focus:border-blue-500/50" />
              </div>
            </div>
          </div>
        </header>

        {/* DADOS CLIENTE */}
        <section className="p-4 md:p-6 bg-white border-b border-slate-100">
          <div className="flex items-center space-x-2 mb-4">
            <User className="w-4 h-4 text-[#002137]" />
            <h2 className="text-[11px] font-black uppercase tracking-widest text-slate-800">Dados do Cliente</h2>
          </div>
          <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
            <div className="col-span-2">
              <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Nome / Razão Social</label>
              <input type="text" name="name" value={clientData.name} onChange={handleClientChange} className="w-full px-2.5 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[10px] font-bold text-slate-700 outline-none" />
            </div>
            <div>
              <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">CPF / CNPJ</label>
              <input type="text" name="cpfCnpj" value={clientData.cpfCnpj} onChange={handleClientChange} className="w-full px-2.5 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[10px] text-slate-600 outline-none" />
            </div>
            <div>
              <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">RG / IE</label>
              <input type="text" name="rgIe" value={clientData.rgIe} onChange={handleClientChange} className="w-full px-2.5 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[10px] text-slate-600 outline-none" />
            </div>
            <div className="col-span-2">
              <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">Endereço Completo</label>
              <input type="text" name="address" value={clientData.address} onChange={handleClientChange} className="w-full px-2.5 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[10px] text-slate-600 outline-none" />
            </div>
            <div className="col-span-2">
              <label className="block text-[8px] font-black text-slate-400 uppercase tracking-widest mb-1">E-mail</label>
              <input type="email" name="email" value={clientData.email} onChange={handleClientChange} className="w-full px-2.5 py-1.5 bg-slate-50 border border-slate-200 rounded-lg text-[10px] text-slate-600 outline-none" />
            </div>
          </div>
        </section>

        {/* INFO ADICIONAL */}
        <section className="px-4 md:px-6 py-3 bg-slate-50 border-b border-slate-100 grid grid-cols-2 gap-4">
          <div className="flex items-center gap-3">
            <Info className="w-4 h-4 text-blue-600 shrink-0" />
            <div className="flex-1">
              <label className="block text-[8px] font-black text-slate-400 uppercase mb-0.5 tracking-tight">Acabamento Selecionado</label>
              <input type="text" value={budgetInfo.color} onChange={(e) => setBudgetInfo(p => ({...p, color: e.target.value}))} className="w-full bg-transparent border-none p-0 text-[10px] font-black text-slate-800 outline-none" />
            </div>
          </div>
          <div className="flex items-center gap-3">
            <Hash className="w-4 h-4 text-blue-600 shrink-0" />
            <div className="flex-1">
              <label className="block text-[8px] font-black text-slate-400 uppercase mb-0.5 tracking-tight">Nota Técnica</label>
              <input type="text" value={budgetInfo.info} onChange={(e) => setBudgetInfo(p => ({...p, info: e.target.value}))} className="w-full bg-transparent border-none p-0 text-[10px] font-black text-slate-800 outline-none" placeholder="Ex: Vidro 10mm" />
            </div>
          </div>
        </section>

        {/* ITENS */}
        <section className="p-4 md:p-6 min-h-[250px]">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center space-x-2">
              <FileText className="w-4 h-4 text-slate-700" />
              <h2 className="text-[11px] font-black uppercase tracking-widest text-slate-800">Descrição do Orçamento</h2>
            </div>
            <button onClick={addItem} className="no-print flex items-center gap-1.5 bg-[#002137] text-white px-3 py-1.5 rounded-lg text-[10px] font-black uppercase shadow-md active:scale-95 transition-colors">
              <Plus className="w-3.5 h-3.5" /> Item
            </button>
          </div>

          <div className="space-y-4">
            {items.map((item) => (
              <div key={item.id} className="item-row flex flex-row items-start gap-4 border border-slate-100 rounded-xl p-3 bg-white relative group">
                <button onClick={() => removeItem(item.id)} className="absolute -top-2 -right-2 no-print text-white bg-red-500 p-1.5 rounded-full shadow-lg opacity-0 group-hover:opacity-100 z-10 transition-opacity">
                  <Trash2 className="w-3.5 h-3.5" />
                </button>

                <div className="w-24 h-24 shrink-0 border-2 border-dashed border-slate-200 rounded-xl flex items-center justify-center overflow-hidden bg-slate-50 relative">
                  {item.image ? (
                    <img src={item.image} alt="Produto" className="w-full h-full object-cover" />
                  ) : (
                    <ImageIcon className="text-slate-300 w-6 h-6" />
                  )}
                  <input type="file" accept="image/*" onChange={(e) => handleImageUpload(item.id, e)} className="absolute inset-0 opacity-0 cursor-pointer no-print" />
                </div>

                <div className="flex-1 flex flex-col justify-between h-24 text-left">
                  <textarea 
                    value={item.description} 
                    onChange={(e) => updateItem(item.id, 'description', e.target.value)} 
                    className="w-full bg-transparent p-0 border-none text-[10px] font-bold text-slate-800 leading-tight resize-none outline-none" 
                    placeholder="Descrição do item..." 
                  />

                  <div className="flex items-end justify-between">
                    <div className="flex gap-4">
                      <div className="w-12">
                        <label className="block text-[7px] font-black text-slate-400 uppercase mb-0.5">Qtd</label>
                        <input type="number" min="1" value={item.quantity} onChange={(e) => updateItem(item.id, 'quantity', Number(e.target.value))} className="w-full bg-slate-50 border border-slate-100 rounded p-0.5 text-[11px] font-black text-center" />
                      </div>
                      <div className="w-28">
                        <label className="block text-[7px] font-black text-slate-400 uppercase mb-0.5">Valor Unitário</label>
                        <div className="flex items-center bg-slate-50 rounded px-1.5 border border-slate-100 h-8">
                          <span className="text-[8px] text-slate-400 font-black mr-1">R$</span>
                          <input type="number" step="0.01" value={item.unitPrice} onChange={(e) => updateItem(item.id, 'unitPrice', Number(e.target.value))} className="w-full bg-transparent border-none py-1 text-[11px] font-black outline-none" />
                        </div>
                      </div>
                    </div>
                    <div className="text-right">
                      <label className="block text-[7px] font-black text-slate-400 uppercase mb-0.5">Total Item</label>
                      <span className="text-[12px] font-black text-slate-900">{formatCurrency(item.quantity * item.unitPrice)}</span>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </section>

        {/* RODAPÉ */}
        <section className="p-4 md:p-6 bg-slate-50 border-t border-slate-100 flex flex-row items-start gap-6 footer-row">
          <div className="flex-1">
            <h3 className="text-[9px] font-black uppercase tracking-widest text-slate-500 mb-2">Observações Importantes</h3>
            <textarea 
              rows={5} 
              value={observations} 
              onChange={(e) => setObservations(e.target.value)} 
              className="w-full bg-white p-3 border border-slate-200 rounded-xl text-[10px] text-slate-600 outline-none leading-relaxed resize-none shadow-sm h-full min-h-[100px]" 
            />
          </div>

          <div className="w-64 shrink-0">
            <div className="bg-[#002137] p-4 rounded-2xl shadow-xl relative overflow-hidden border border-white/5">
              <span className="text-blue-300 text-[8px] font-black uppercase tracking-widest mb-1 block leading-none uppercase">VALOR TOTAL PROJETO</span>
              <span className="text-white text-2xl font-black tracking-tighter block leading-none py-1">
                {formatCurrency(total)}
              </span>
              <div className="mt-3 pt-3 border-t border-white/10">
                <p className="text-[8px] font-black text-blue-200 italic uppercase leading-tight">
                  Sujeito a alteração após medição.
                </p>
              </div>
            </div>
            <p className="mt-3 text-[7px] text-slate-400 text-center uppercase font-black tracking-widest leading-none">
              Validade do Orçamento: 15 dias • Casa dos Vidros
            </p>
          </div>
        </section>

        <footer className="py-2.5 text-center border-t border-slate-50 bg-white">
          <p className="text-[8px] font-black text-slate-300 uppercase tracking-[0.4em]">
            © 2025 • ORÇAMENTO DIGITAL • {COMPANY_INFO.name}
          </p>
        </footer>
      </div>

      {/* AÇÕES FIXAS */}
      <div className="max-w-4xl mx-auto mt-6 flex flex-row gap-4 justify-center no-print px-4">
        <button 
          onClick={() => window.print()} 
          className="flex-1 max-w-[220px] flex items-center justify-center gap-2 bg-[#002137] text-white px-5 py-3.5 rounded-xl shadow-lg font-black uppercase text-[10px] active:scale-95 transition-all hover:bg-black"
        >
          <Printer className="w-4 h-4" /> Gerar PDF / Imprimir
        </button>

        <button 
          onClick={handleShareQuoteAsImage} 
          disabled={isSharing}
          className={`flex-1 max-w-[220px] flex items-center justify-center gap-2 ${isSharing ? 'bg-slate-400' : 'bg-[#25D366] hover:bg-[#128C7E]'} text-white px-5 py-3.5 rounded-xl shadow-lg font-black uppercase text-[10px] active:scale-95 transition-all`}
        >
          <Share2 className="w-4 h-4" /> {isSharing ? "Gerando..." : "Enviar Foto"}
        </button>
      </div>

      {/* HISTÓRICO DE ORÇAMENTOS (BANCO DE DADOS) */}
      <div className="max-w-4xl mx-auto mt-12 no-print px-4 pb-20">
        <div className="flex items-center gap-2 mb-6 border-b border-slate-200 pb-2">
          <History className="w-5 h-5 text-slate-400" />
          <h2 className="text-sm font-black text-slate-500 uppercase tracking-widest">Histórico de Orçamentos (Salvos Localmente)</h2>
        </div>

        {savedQuotes.length === 0 ? (
          <div className="bg-white rounded-2xl p-8 border border-dashed border-slate-300 text-center text-slate-400">
            <p className="text-sm font-bold italic">Nenhum orçamento salvo no banco de dados local ainda.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {savedQuotes.map((q) => (
              <div 
                key={q.id} 
                onClick={() => loadQuote(q)}
                className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm hover:shadow-md hover:border-blue-200 transition-all cursor-pointer group relative overflow-hidden"
              >
                <div className="absolute top-0 right-0 p-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={(e) => deleteQuote(q.id, e)} className="p-1.5 bg-red-50 text-red-500 rounded-lg hover:bg-red-500 hover:text-white transition-all shadow-sm">
                    <Trash2 className="w-3.5 h-3.5" />
                  </button>
                </div>

                <div className="flex flex-col gap-2">
                  <div className="flex items-center justify-between">
                    <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-2 py-0.5 rounded-full">Nº {q.clientData.quoteNumber}</span>
                    <span className="text-[9px] font-bold text-slate-400 uppercase">{new Date(q.timestamp).toLocaleDateString('pt-BR')}</span>
                  </div>

                  <h3 className="text-[12px] font-black text-slate-800 uppercase line-clamp-1 leading-tight">{q.clientData.name || "Cliente sem nome"}</h3>

                  <div className="flex items-center justify-between mt-2 pt-2 border-t border-slate-50">
                    <div className="flex items-center gap-1">
                      <FileText className="w-3 h-3 text-slate-300" />
                      <span className="text-[9px] font-bold text-slate-400 uppercase">{q.items.length} {q.items.length === 1 ? 'item' : 'itens'}</span>
                    </div>
                    <span className="text-[11px] font-black text-[#002137]">{formatCurrency(q.items.reduce((acc, i) => acc + (i.quantity * i.unitPrice), 0))}</span>
                  </div>
                </div>

                <div className="mt-3 flex gap-2">
                   <button className="flex-1 flex items-center justify-center gap-1 bg-slate-50 text-slate-600 py-1.5 rounded-lg text-[8px] font-black uppercase group-hover:bg-blue-600 group-hover:text-white transition-colors">
                     <Download className="w-2.5 h-2.5" /> Abrir Orçamento
                   </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

export interface ClientData {
  name: string;
  address: string;
  city: string;
  uf: string;
  phone: string; // Este é o telefone da empresa no contexto atual, mas ClientData geralmente refere-se ao cliente
  cep: string;
  cpfCnpj: string;
  clientPhone: string; // Novo campo substituindo RG/IE
  email: string;
  obs: string;
  date: string;
  quoteNumber: string;
}

export interface QuoteItem {
  id: string;
  description: string;
  quantity: number;
  unitPrice: number;
  image?: string;
  notes?: string;
}

export interface CompanyInfo {
  name: string;
  owner: string;
  address: string;
  cep: string;
  city: string;
  cnpj: string;
  phone: string;
}

export interface SavedQuote {
  id: string;
  timestamp: number;
  clientData: ClientData;
  items: QuoteItem[];
  budgetInfo: {
    color: string;
    info: string;
  };
  observations: string;
}

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Plus, Trash2, Printer, Image as ImageIcon, User, FileText, Info, MessageCircle, Hash, Share2, Save, History, RotateCcw, Download, Phone } from 'lucide-react';
import { ClientData, QuoteItem, SavedQuote } from './types';
import { COMPANY_INFO, DEFAULT_OBSERVATIONS } from './constants';

const CompanyLogo = () => {
  return (
    <div className="relative shrink-0">
      <div className="relative w-16 h-16 md:w-24 md:h-24 rounded-full overflow-hidden shadow-lg border-2 border-white/10 bg-[#002137] flex items-center justify-center">
        <svg viewBox="0 0 400 400" className="w-full h-full p-2">
          <circle cx="200" cy="200" r="190" fill="#002137" />
          <defs>
            <linearGradient id="glassGrad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#6ea8fe" />
              <stop offset="100%" stopColor="#0d6efd" />
            </linearGradient>
          </defs>
          <g transform="translate(60, 130) scale(0.9)">
            <rect x="0" y="0" width="80" height="140" fill="url(#glassGrad)" opacity="0.9" transform="skewY(-15)" />
            <rect x="25" y="10" width="80" height="140" fill="url(#glassGrad)" opacity="0.7" transform="skewY(-15)" />
            <rect x="50" y="20" width="80" height="140" fill="url(#glassGrad)" opacity="0.5" transform="skewY(-15)" />
          </g>
          <g transform="translate(160, 160)">
            <path d="M10,0 L140,0 L180,45 L140,90 L10,90 Z" fill="none" stroke="white" strokeWidth="6" strokeLinejoin="round" />
            <text x="15" y="38" fontFamily="Arial, sans-serif" fontWeight="900" fontSize="32" fill="white">Casa dos</text>
            <text x="15" y="75" fontFamily="Arial, sans-serif" fontWeight="900" fontSize="48" fill="white">Vidros</text>
            <text x="55" y="105" fontFamily="Arial, sans-serif" fontWeight="bold" fontSize="14" fill="white" letterSpacing="2">VIDRAÇARIA</text>
          </g>
        </svg>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const today = new Date().toLocaleDateString('pt-BR');

  // Estados principais
  const [clientData, setClientData] = useState<ClientData>({
    name: '',
    address: '',
    city: 'LIMEIRA',
    uf: 'SP',
    phone: '',
    cep: '',
    cpfCnpj: '',
    clientPhone: '', // Substituído rgIe
    email: '',
    obs: '',
    date: today,
    quoteNumber: '',
  });

  const [budgetInfo, setBudgetInfo] = useState({
    color: 'Vidro incolor, alumínio branco',
    info: ''
  });

  const [items, setItems] = useState<QuoteItem[]>([
    { id: '1', description: '', quantity: 1, unitPrice: 0 }
  ]);

  const [observations, setObservations] = useState(DEFAULT_OBSERVATIONS);
  const [savedQuotes, setSavedQuotes] = useState<SavedQuote[]>([]);
  const [isSharing, setIsSharing] = useState(false);

  // Carregar do "Banco de Dados" (LocalStorage) ao iniciar
  useEffect(() => {
    const data = localStorage.getItem('casa_dos_vidros_db');
    if (data) {
      setSavedQuotes(JSON.parse(data));
    }
  }, []);

  const total = useMemo(() => items.reduce((acc, item) => acc + (item.quantity * item.unitPrice), 0), [items]);

  const handleClientChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setClientData(prev => ({ ...prev, [name]: value }));
  };

  const addItem = () => {
    setItems(prev => [...prev, { id: Math.random().toString(36).substr(2, 9), description: '', quantity: 1, unitPrice: 0 }]);
  };

  const removeItem = (id: string) => items.length > 1 && setItems(prev => prev.filter(item => item.id !== id));

  const updateItem = (id: string, field: keyof QuoteItem, value: any) => {
    setItems(prev => prev.map(item => item.id === id ? { ...item, [field]: value } : item));
  };

  const handleImageUpload = (id: string, e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => updateItem(id, 'image', reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const formatCurrency = (value: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(value);

  // Funções do "Banco de Dados"
  const saveQuote = () => {
    if (!clientData.name || !clientData.quoteNumber) {
      alert("Por favor, preencha pelo menos o Nome do Cliente e o Nº do Orçamento.");
      return;
    }

    const newSavedQuote: SavedQuote = {
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now(),
      clientData,
      items,
      budgetInfo,
      observations
    };

    const updated = [newSavedQuote, ...savedQuotes];
    setSavedQuotes(updated);
    localStorage.setItem('casa_dos_vidros_db', JSON.stringify(updated));
    alert("Orçamento salvo no histórico com sucesso!");
  };

  const loadQuote = (quote: SavedQuote) => {
    if (confirm("Deseja carregar este orçamento? Isso substituirá o que está na tela.")) {
      setClientData(quote.clientData);
      setItems(quote.items);
      setBudgetInfo(quote.budgetInfo);
      setObservations(quote.observations);
      window.scrollTo(0, 0);
    }
  };

  const deleteQuote = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm("Excluir este orçamento permanentemente?")) {
      const updated = savedQuotes.filter(q => q.id !== id);
      setSavedQuotes(updated);
      localStorage.setItem('casa_dos_vidros_db', JSON.stringify(updated));
    }
  };

  const newQuote = () => {
    if (confirm("Limpar tudo e iniciar um novo orçamento?")) {
      setClientData({ ...clientData, name: '', cpfCnpj: '', address: '', email: '', clientPhone: '', quoteNumber: '', date: today });
      setItems([{ id: '1', description: '', quantity: 1, unitPrice: 0 }]);
      setBudgetInfo({ color: 'Vidro incolor, alumínio branco', info: '' });
      setObservations(DEFAULT_OBSERVATIONS);
    }
  };

  const handleShareQuoteAsImage = async () => {
    const element = containerRef.current;
    if (!element) return;

    setIsSharing(true);
    try {
      window.scrollTo(0, 0);
      const canvas = await (window as any).html2canvas(element, {
        scale: 2.5,
        useCORS: true,
        allowTaint: true,
        backgroundColor: '#ffffff',
        logging: false,
        onclone: (clonedDoc: Document) => {
          const noPrint = clonedDoc.querySelectorAll('.no-print');
          noPrint.forEach(el => (el as HTMLElement).style.display = 'none');

          const container = clonedDoc.getElementById('quote-container');
          if (container) {
            container.style.boxShadow = 'none';
            container.style.border = 'none';
            container.style.borderRadius = '0';
            container.style.width = '1000px'; 
          }
          // Garante alinhamento forçado no clone
          const rightSide = clonedDoc.querySelector('.header-right-side') as HTMLElement;
          if (rightSide) {
             rightSide.style.display = 'flex';
             rightSide.style.flexDirection = 'column';
             rightSide.style.alignItems = 'flex-end';
             rightSide.style.textAlign = 'right';
          }
        }
      });

      canvas.toBlob(async (blob: Blob | null) => {
        if (!blob) throw new Error("Falha ao gerar imagem");
        const fileName = `Orcamento_${clientData.quoteNumber || 'Novo'}.png`;
        const file = new File([blob], fileName, { type: 'image/png' });

        if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
          await navigator.share({ files: [file], title: `Orçamento ${clientData.quoteNumber}` });
        } else {
          const url = URL.createObjectURL(blob);
          const link = document.createElement('a');
          link.href = url;
          link.download = fileName;
          link.click();
          URL.revokeObjectURL(url);
        }
      }, 'image/png');
    } catch (err) {
      console.error(err);
      alert("Erro ao capturar orçamento.");
    } finally {
      setIsSharing(false);
    }
  };

  return (
    <div className="min-h-screen py-4 md:py-8 px-2 sm:px-4 bg-[#f1f5f9]">
      {/* BARRA DE AÇÕES SUPERIOR */}
      <div className="max-w-4xl mx-auto mb-6 flex justify-between items-center no-print">
         <div className="flex gap-2">
            <button onClick={newQuote} className="flex items-center gap-2 bg-white text-slate-700 px-4 py-2 rounded-xl shadow-sm border border-slate-200 font-bold text-[10px] uppercase hover:bg-slate-50 transition-all">
              <RotateCcw className="w-4 h-4 text-blue-500" /> Novo Orçamento
            </button>
            <button onClick={saveQuote} className="flex items-center gap-2 bg-[#002137] text-white px-4 py-2 rounded-xl shadow-md font-bold text-[10px] uppercase hover:bg-black transition-all">
              <Save className="w-4 h-4 text-blue-400" /> Salvar Orçamento
            </button>
         </div>
      </div>

      <div 
        ref={containerRef}
        id="quote-container" 
        className="max-w-4xl mx-auto bg-white shadow-2xl md:rounded-2xl overflow-hidden border border-slate-200 print:border-none print:shadow-none"
      >

        {/* CABEÇALHO */}
        <header className="bg-[#002137] text-white p-4 md:p-6 flex flex-row items-center gap-4 md:gap-6 relative header-info-container">
          <CompanyLogo />

          <div className="flex-1 flex flex-col justify-center text-left">
            <h1 className="text-xl md:text-2xl font-black tracking-tighter uppercase mb-0.5 bg-gradient-to-r from-white to-blue-100 bg-clip-text text-transparent leading-none">
              {COMPANY_INFO.name}
            </h1>
            <p className="text-slate-300 text-[10px] md:text-[11px] font-medium uppercase tracking-tight leading-tight mb-2">
              {COMPANY_INFO.address}
            </p>
            <div className="flex flex-col gap-1 text-[9px] text-slate-400 font-bold uppercase tracking-wider border-t border-white/5 pt-2">
              <span className="flex items-center gap-2">
                CNPJ: <span className="text-slate-200">{COMPANY_INFO.cnpj}</span> 
                <span className="text-slate-600">•</span> {COMPANY_INFO.city}
              </span>
