          <div className="w-64 shrink-0">
            <div className="bg-[#002137] p-4 rounded-2xl shadow-xl relative overflow-hidden border border-white/5">
              <span className="text-blue-300 text-[8px] font-black uppercase tracking-widest mb-1 block leading-none uppercase">VALOR TOTAL PROJETO</span>
              <span className="text-white text-2xl font-black tracking-tighter block leading-none py-1">
                {formatCurrency(total)}
              </span>
              <div className="mt-3 pt-3 border-t border-white/10">
                <p className="text-[8px] font-black text-blue-200 italic uppercase leading-tight">
                  Sujeito a alteração após medição.
                </p>
              </div>
            </div>
            <p className="mt-3 text-[7px] text-slate-400 text-center uppercase font-black tracking-widest leading-none">
              Validade do Orçamento: 15 dias • Casa dos Vidros
            </p>
          </div>
        </section>

        <footer className="py-2.5 text-center border-t border-slate-50 bg-white">
          <p className="text-[8px] font-black text-slate-300 uppercase tracking-[0.4em]">
            © 2025 • ORÇAMENTO DIGITAL • {COMPANY_INFO.name}
          </p>
        </footer>
      </div>

      {/* AÇÕES FIXAS */}
      <div className="max-w-4xl mx-auto mt-6 flex flex-row gap-4 justify-center no-print px-4">
        <button 
          onClick={() => window.print()} 
          className="flex-1 max-w-[220px] flex items-center justify-center gap-2 bg-[#002137] text-white px-5 py-3.5 rounded-xl shadow-lg font-black uppercase text-[10px] active:scale-95 transition-all hover:bg-black"
        >
          <Printer className="w-4 h-4" /> Gerar PDF / Imprimir
        </button>

        <button 
          onClick={handleShareQuoteAsImage} 
          disabled={isSharing}
          className={`flex-1 max-w-[220px] flex items-center justify-center gap-2 ${isSharing ? 'bg-slate-400' : 'bg-[#25D366] hover:bg-[#128C7E]'} text-white px-5 py-3.5 rounded-xl shadow-lg font-black uppercase text-[10px] active:scale-95 transition-all`}
        >
          <Share2 className="w-4 h-4" /> {isSharing ? "Gerando..." : "Enviar Foto"}
        </button>
      </div>

      {/* HISTÓRICO DE ORÇAMENTOS (BANCO DE DADOS) */}
      <div className="max-w-4xl mx-auto mt-12 no-print px-4 pb-20">
        <div className="flex items-center gap-2 mb-6 border-b border-slate-200 pb-2">
          <History className="w-5 h-5 text-slate-400" />
          <h2 className="text-sm font-black text-slate-500 uppercase tracking-widest">Histórico de Orçamentos (Salvos Localmente)</h2>
        </div>

        {savedQuotes.length === 0 ? (
          <div className="bg-white rounded-2xl p-8 border border-dashed border-slate-300 text-center text-slate-400">
            <p className="text-sm font-bold italic">Nenhum orçamento salvo no banco de dados local ainda.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {savedQuotes.map((q) => (
              <div 
                key={q.id} 
                onClick={() => loadQuote(q)}
                className="bg-white p-4 rounded-2xl border border-slate-200 shadow-sm hover:shadow-md hover:border-blue-200 transition-all cursor-pointer group relative overflow-hidden"
              >
                <div className="absolute top-0 right-0 p-2 opacity-0 group-hover:opacity-100 transition-opacity">
                  <button onClick={(e) => deleteQuote(q.id, e)} className="p-1.5 bg-red-50 text-red-500 rounded-lg hover:bg-red-500 hover:text-white transition-all shadow-sm">
                    <Trash2 className="w-3.5 h-3.5" />
                  </button>
                </div>

                <div className="flex flex-col gap-2">
                  <div className="flex items-center justify-between">
                    <span className="text-[10px] font-black text-blue-600 bg-blue-50 px-2 py-0.5 rounded-full">Nº {q.clientData.quoteNumber}</span>
                    <span className="text-[9px] font-bold text-slate-400 uppercase">{new Date(q.timestamp).toLocaleDateString('pt-BR')}</span>
                  </div>

                  <h3 className="text-[12px] font-black text-slate-800 uppercase line-clamp-1 leading-tight">{q.clientData.name || "Cliente sem nome"}</h3>

                  <div className="flex items-center justify-between mt-2 pt-2 border-t border-slate-50">
                    <div className="flex items-center gap-1">
                      <FileText className="w-3 h-3 text-slate-300" />
                      <span className="text-[9px] font-bold text-slate-400 uppercase">{q.items.length} {q.items.length === 1 ? 'item' : 'itens'}</span>
                    </div>
                    <span className="text-[11px] font-black text-[#002137]">{formatCurrency(q.items.reduce((acc, i) => acc + (i.quantity * i.unitPrice), 0))}</span>
                  </div>
                </div>

                <div className="mt-3 flex gap-2">
                   <button className="flex-1 flex items-center justify-center gap-1 bg-slate-50 text-slate-600 py-1.5 rounded-lg text-[8px] font-black uppercase group-hover:bg-blue-600 group-hover:text-white transition-colors">
                     <Download className="w-2.5 h-2.5" /> Abrir Orçamento
                   </button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Plus, Trash2, Printer, Image as ImageIcon, User, FileText, Info, MessageCircle, Hash, Share2, Save, History, RotateCcw, Download, Phone } from 'lucide-react';
import { ClientData, QuoteItem, SavedQuote } from './types';
import { COMPANY_INFO, DEFAULT_OBSERVATIONS } from './constants';

const CompanyLogo = () => {
  return (
    <div className="relative shrink-0">
      <div className="relative w-16 h-16 md:w-24 md:h-24 rounded-full overflow-hidden shadow-lg border-2 border-white/10 bg-[#002137] flex items-center justify-center">
