                <div className="mt-3 flex gap-2">
                   <button className="flex-1 flex items-center justify-center gap-1 bg-slate-50 text-slate-600 py-1.5 rounded-lg text-[8px] font-black uppercase group-hover:bg-blue-600 group-hover:text-white transition-colors">
